// ---------- Flashback-style thread rendering ----------
function fbRand(seed) {
  const x = Math.sin(seed * 12.9898 + 78.233) * 43758.5453;
  return x - Math.floor(x);
}

const FB_MONTHS = ["jan", "feb", "mar", "apr", "maj", "jun", "jul", "aug", "sep", "okt", "nov", "dec"];
const FB_CATEGORIES = [
  ["Hem, bostad & familj", "Mat och dryck"],
  ["Livsstil", "Kropp och hälsa"],
  ["Resor och semester", "Resmål och resetips"],
  ["Dator och IT", "Hårdvara"],
  ["Sport, hobby och fritid", "Sällskapsspel"],
  ["Vardagsprat", "Off topic"],
  ["Konsument", "Elektronik och prylar"],
  ["Livsstil", "Träning och kost"],
];

function fbPad(n) { return (n < 10 ? "0" : "") + n; }

function fbThreadDate(threadIdx) {
  return {
    year: 2017 + Math.floor(fbRand(threadIdx * 5 + 3) * 7), // 2017–2023
    monthIdx: Math.floor(fbRand(threadIdx * 5 + 2) * 12),
    day: 1 + Math.floor(fbRand(threadIdx * 5 + 1) * 27),
  };
}

function fbTimestamp(threadIdx, postIdx) {
  const d = fbThreadDate(threadIdx);
  let minutes = 9 * 60 + Math.floor(fbRand(threadIdx * 5 + 4) * 9 * 60);
  for (let i = 0; i < postIdx; i++) minutes += 6 + Math.floor(fbRand(threadIdx * 40 + i) * 190);
  minutes = minutes % (24 * 60);
  return `${d.year}-${fbPad(d.monthIdx + 1)}-${fbPad(d.day)}, ${fbPad(Math.floor(minutes / 60))}:${fbPad(minutes % 60)}`;
}

function fbThreadTitle(q) {
  const text = (q || "").trim().replace(/\s+/g, " ");
  const m = text.match(/^.{0,85}?[.?!]/);
  let t = (m ? m[0] : text).trim();
  if (t.length > 80) t = t.slice(0, 78).trim() + "…";
  return t || "Tråd";
}

function fbAvatar(hue) {
  const wrap = document.createElement("div");
  wrap.className = "fb-avatar";
  wrap.style.background = `hsl(${hue}, 46%, 64%)`;
  wrap.innerHTML =
    '<svg viewBox="0 0 40 40" aria-hidden="true">' +
    '<circle cx="20" cy="15" r="7.5" fill="#ffffff" opacity="0.92"/>' +
    '<path d="M7 40c0-8 6-13 13-13s13 5 13 13z" fill="#ffffff" opacity="0.92"/></svg>';
  return wrap;
}

function fbPost(opts) {
  const post = document.createElement("article");
  post.className = "fb-post" + (opts.isOp ? " fb-post--op" : "") +
    (opts.num % 2 === 0 ? " fb-post--alt" : "");

  const side = document.createElement("div");
  side.className = "fb-side";
  const uname = document.createElement("div");
  uname.className = "fb-user";
  uname.textContent = opts.name;
  side.appendChild(uname);
  const rank = document.createElement("div");
  rank.className = "fb-rank";
  rank.innerHTML = '<span class="fb-online"></span> Medlem';
  side.appendChild(rank);
  // Distinct avatar colour per user (hues spaced ~67° apart within a thread).
  side.appendChild(fbAvatar((opts.threadIdx * 40 + opts.num * 67) % 360));

  const main = document.createElement("div");
  main.className = "fb-main";
  const head = document.createElement("div");
  head.className = "fb-post-head";
  const date = document.createElement("span");
  date.className = "fb-date";
  date.textContent = fbTimestamp(opts.threadIdx, opts.postIdx);
  const num = document.createElement("span");
  num.className = "fb-num";
  num.textContent = "#" + opts.num;
  head.appendChild(date);
  head.appendChild(num);
  main.appendChild(head);

  const body = document.createElement("div");
  body.className = "fb-body";
  body.textContent = opts.body;
  main.appendChild(body);

  const foot = document.createElement("div");
  foot.className = "fb-post-foot";
  const quote = document.createElement("span");
  quote.className = "fb-quote";
  quote.textContent = "Citera";
  foot.appendChild(quote);
  main.appendChild(foot);

  post.appendChild(side);
  post.appendChild(main);

  // Reply posts get a prominent right-hand judgement column.
  if (typeof opts.commentIdx === "number") {
    const ans = opts.ans;
    const jcol = document.createElement("div");
    jcol.className = "fb-judge-col";
    const title = document.createElement("div");
    title.className = "fb-judge-title";
    title.textContent = "Skrivet av?";
    const bH = document.createElement("button");
    bH.type = "button";
    bH.className = "fb-judge-btn" + (ans && ans.choiceIsHuman === true ? " selected" : "");
    bH.textContent = "Människa";
    bH.addEventListener("click", () => inlineRecordAnswer(opts.commentIdx, true));
    const bA = document.createElement("button");
    bA.type = "button";
    bA.className = "fb-judge-btn" + (ans && ans.choiceIsHuman === false ? " selected" : "");
    bA.textContent = "AI";
    bA.addEventListener("click", () => inlineRecordAnswer(opts.commentIdx, false));
    jcol.appendChild(title);
    jcol.appendChild(bH);
    jcol.appendChild(bA);
    post.appendChild(jcol);
  }

  return post;
}

// Restore the standard question area / controls after leaving the thread view.
function resetThreadChrome() {
  if (els.questionHeader) els.questionHeader.style.display = "";
  if (els.questionText) els.questionText.style.display = "";
  if (els.commentsContainer) els.commentsContainer.className = "comments-container";
  els.btnNext.hidden = false;
  els.btnNext.style.display = "";
}

function renderThread() {
  const thread = THREADS[currentThreadIndex];
  if (!thread) return;

  hideChoices(true);
  els.btnExit.hidden = false;
  els.btnExit.style.display = "";
  // The Flashback thread renders the question as the OP post, so hide the
  // default question header/text area. Use style.display because .question-header
  // sets display:flex, which would override the [hidden] attribute.
  if (els.questionHeader) els.questionHeader.style.display = "none";
  if (els.questionTitle) els.questionTitle.hidden = true;
  if (els.questionText) els.questionText.style.display = "none";

  if (!redditAnswers[currentThreadIndex]) {
    redditAnswers[currentThreadIndex] = thread.comments.map(() => null);
  }
  const threadAnswers = redditAnswers[currentThreadIndex];

  if (els.subtitle) {
    els.subtitle.textContent =
      "Läs tråden. Avgör för varje inlägg om det är skrivet av en människa eller av en AI.";
  }

  const answeredCount = threadAnswers.filter(a => a !== null).length;
  const allAnswered = answeredCount === thread.comments.length;

  const c = els.commentsContainer;
  if (c) {
    c.className = "comments-container fb-mode";
    c.innerHTML = "";

    const cat = FB_CATEGORIES[currentThreadIndex % FB_CATEGORIES.length];
    const crumb = document.createElement("div");
    crumb.className = "fb-crumb";
    crumb.innerHTML =
      `<span class="fb-crumb-dot"></span> ${cat[0]} <span class="fb-crumb-sep">/</span> ${cat[1]}`;
    c.appendChild(crumb);

    const title = document.createElement("h2");
    title.className = "fb-title";
    title.textContent = fbThreadTitle(thread.questionText);
    c.appendChild(title);

    // OP post = the thread question
    c.appendChild(fbPost({
      num: 1, name: "Trådskapare", seed: currentThreadIndex * 101 + 1,
      threadIdx: currentThreadIndex, postIdx: 0, body: thread.questionText, isOp: true,
    }));

    // Reply posts = the comments to judge
    thread.comments.forEach((comment, idx) => {
      c.appendChild(fbPost({
        num: idx + 2, name: "Användare " + (idx + 1), seed: currentThreadIndex * 101 + idx + 2,
        threadIdx: currentThreadIndex, postIdx: idx + 1, body: comment.text,
        commentIdx: idx, ans: threadAnswers[idx],
      }));
    });

    // Bottom-right pager with the next-thread arrow
    const pager = document.createElement("div");
    pager.className = "fb-pager";
    const info = document.createElement("span");
    info.className = "fb-page-info";
    info.textContent = allAnswered
      ? (currentThreadIndex === THREADS.length - 1 ? "Alla inlägg bedömda" : "Alla inlägg bedömda – gå vidare")
      : `${answeredCount}/${thread.comments.length} inlägg bedömda`;
    const nextArrow = document.createElement("button");
    nextArrow.type = "button";
    nextArrow.className = "fb-next" + (allAnswered ? "" : " fb-next--off");
    nextArrow.disabled = !allAnswered;
    nextArrow.title = currentThreadIndex === THREADS.length - 1 ? "Nästa del" : "Nästa tråd";
    nextArrow.setAttribute("aria-label", nextArrow.title);
    nextArrow.textContent = "›";
    nextArrow.addEventListener("click", handleNext);
    pager.appendChild(info);
    pager.appendChild(nextArrow);
    c.appendChild(pager);
  }

  els.progressText.textContent = `Tråd ${currentThreadIndex + 1} av ${THREADS.length} · ${answeredCount}/${thread.comments.length} bedömda`;
  const progressRatio = thread.comments.length > 0 ? answeredCount / thread.comments.length : 0;
  els.progressBarInner.style.width = `${Math.round(progressRatio * 100)}%`;
  els.btnPrev.disabled = currentThreadIndex === 0;
  // The next control is now the bottom-right arrow inside the thread.
  els.btnNext.hidden = true;
  els.btnNext.style.display = "none";
  els.feedback.textContent = "";
  els.feedback.classList.remove("correct", "incorrect");
}

function inlineRecordAnswer(commentIdx, choiceIsHuman) {
  if (redditShowingFeedback) return;
  if (!redditAnswers[currentThreadIndex]) {
    redditAnswers[currentThreadIndex] = THREADS[currentThreadIndex].comments.map(() => null);
  }
  redditAnswers[currentThreadIndex][commentIdx] = { choiceIsHuman };
  renderThread();
}

function renderTransition() {
  resetThreadChrome();
  els.btnExit.hidden = false;
  els.btnExit.style.display = "";

  if (els.subtitle) {
    els.subtitle.textContent =
      "Nu börjar nästa del: bedöm uppsatsabstrakt. Läs noggrant och avgör om texten är skriven av en människa eller AI.";
  }
  if (els.questionTitle) els.questionTitle.hidden = true;

  els.questionLabel.textContent = "Nästa del";
  els.questionTag.textContent = "Instruktion";
  els.questionText.textContent =
    "Du har nu bedömt kommentarer i en diskussionstråd. I nästa del får du läsa uppsatsabstrakt ett i taget och avgöra om de är skrivna av en människa eller av en AI.";

  if (els.commentsContainer) {
    els.commentsContainer.innerHTML = "";
  }

  els.progressText.textContent = "";
  els.progressBarInner.style.width = "0%";

  resetChoiceStyles();
  els.feedback.textContent = "";
  els.feedback.classList.remove("correct", "incorrect");

  hideChoices(true);
  els.btnPrev.disabled = false;
  els.btnNext.disabled = false;
  els.btnNext.textContent = "Starta abstrakt-delen ▶";

  updateScoreSummary();
}

function makeScoreBar(label, correct, answered) {
  const pct = answered > 0 ? Math.round((correct / answered) * 100) : 0;
  const wrap = document.createElement("div");
  wrap.className = "outro-score-block";

  const labelRow = document.createElement("div");
  labelRow.className = "outro-score-label";
  labelRow.innerHTML = `<span>${label}</span><span class="outro-score-fraction">${correct} / ${answered} (${pct}%)</span>`;
  wrap.appendChild(labelRow);

  const barOuter = document.createElement("div");
  barOuter.className = "outro-bar-outer";
  const barInner = document.createElement("div");
  barInner.className = "outro-bar-inner";
  barInner.style.width = "0%";
  barOuter.appendChild(barInner);
  wrap.appendChild(barOuter);

  // Animate bar after paint
  requestAnimationFrame(() => requestAnimationFrame(() => {
    barInner.style.width = `${pct}%`;
  }));

  return wrap;
}

function renderOutro() {
  resetThreadChrome();
  hideChoices(true);
  if (els.questionTitle) els.questionTitle.hidden = true;
  els.btnExit.hidden = true;
  els.btnExit.style.display = "none";

  if (els.subtitle) {
    els.subtitle.textContent = "Tack för att du deltog!";
  }

  els.questionLabel.textContent = "Klart";
  els.questionTag.textContent = "Tack";

  const sections = computeSectionScores();
  const totals = computeTotalScoreSoFar();

  els.questionText.classList.add("question-text--intro");
  els.questionText.innerHTML =
    "<p>Tack för att du har genomfört undersökningen! :) </p>" +
    "<p>Nedan ser du dina resultat för varje del.</p>";

  if (els.commentsContainer) {
    els.commentsContainer.innerHTML = "";

    // Score bars
    const scoresWrap = document.createElement("div");
    scoresWrap.className = "outro-scores";
    scoresWrap.appendChild(makeScoreBar("Kommentarer", sections.comments.correct, sections.comments.answered));
    scoresWrap.appendChild(makeScoreBar("Abstrakt", sections.abstracts.correct, sections.abstracts.answered));
    scoresWrap.appendChild(makeScoreBar("Totalt", totals.correct, totals.answered));
    els.commentsContainer.appendChild(scoresWrap);

    // ---- Answer key: reveal each item's true label and whether the guess was right ----
    function buildReviewRow(text, actualIsHuman, guessIsHuman) {
      const isCorrect = guessIsHuman === actualIsHuman;
      const row = document.createElement("div");
      row.className = "comment-row " + (isCorrect ? "comment-row--correct" : "comment-row--incorrect");
      const meta = document.createElement("div");
      meta.className = "comment-meta";
      const actual = actualIsHuman ? "Människa" : "AI";
      const guess = guessIsHuman ? "Människa" : "AI";
      meta.textContent = `${isCorrect ? "Rätt" : "Fel"} — Rätt svar: ${actual} · Ditt svar: ${guess}`;
      row.appendChild(meta);
      const body = document.createElement("div");
      body.className = "comment-body";
      body.textContent = text;
      row.appendChild(body);
      return row;
    }

    const review = document.createElement("div");
    review.className = "outro-review";
    review.style.cssText = "margin-top:1.5rem;display:flex;flex-direction:column;gap:0.6rem;";

    const revIntro = document.createElement("p");
    revIntro.className = "outro-refl-label";
    revIntro.textContent = "Facit: här ser du vilka texter som var skrivna av AI respektive människa, och vad du svarade.";
    review.appendChild(revIntro);

    const cHead = document.createElement("h3");
    cHead.textContent = "Kommentarer";
    cHead.style.cssText = "margin:0.6rem 0 0;font-size:clamp(1rem,2.6vw,1.15rem);";
    review.appendChild(cHead);

    THREADS.forEach((thread, t) => {
      const ta = redditAnswers[t];
      if (!ta || ta.every(a => a === null)) return;
      const qLabel = document.createElement("div");
      qLabel.style.cssText = "font-weight:600;margin-top:0.5rem;font-size:clamp(0.85rem,2.3vw,0.95rem);";
      qLabel.textContent = `Tråd ${t + 1}: ${thread.questionText}`;
      review.appendChild(qLabel);
      thread.comments.forEach((c, i) => {
        if (!ta[i]) return;
        review.appendChild(buildReviewRow(c.text, c.isHuman, ta[i].choiceIsHuman));
      });
    });

    const aHead = document.createElement("h3");
    aHead.textContent = "Abstrakt";
    aHead.style.cssText = "margin:1rem 0 0;font-size:clamp(1rem,2.6vw,1.15rem);";
    review.appendChild(aHead);

    effectiveQuestions.forEach((q, i) => {
      if (!answers[i]) return;
      const label = (q.title && q.title.trim()) ? q.title.trim() : q.text;
      review.appendChild(buildReviewRow(label, q.isHuman, answers[i].choiceIsHuman));
    });

    els.commentsContainer.appendChild(review);

    // Reflection box
    const box = document.createElement("div");
    box.className = "outro-box";

    const reflLabel = document.createElement("p");
    reflLabel.className = "outro-refl-label";
    reflLabel.textContent = "Fanns det några tecken som fick dig att tro att en text var skriven av AI snarare än en människa? (frivilligt)";
    box.appendChild(reflLabel);

    const textarea = document.createElement("textarea");
    textarea.className = "outro-textarea";
    textarea.placeholder = "Skriv valfri motivering här...";
    textarea.rows = 4;
    box.appendChild(textarea);

    const actions = document.createElement("div");
    actions.className = "outro-actions";

    const submit = document.createElement("button");
    submit.type = "button";
    submit.className = "nav-button primary";
    submit.textContent = "Skicka reflektion";

    submit.addEventListener("click", async () => {
      const text = textarea.value.trim();
      if (!text) return;

      globalQuestionIndex += 1;
      const payload = {
        participantId: PARTICIPANT_ID,
        response: {
          questionIndex: globalQuestionIndex,
          questionType: "reasoning",
          questionText: text,
          isHumanLabel: "",
          userGuessIsHuman: "",
          isCorrect: "",
          totalCorrectSoFar: totals.correct,
          totalAnsweredSoFar: totals.answered,
          mode: "outro",
        },
      };

      try {
        await fetch(RESULTS_ENDPOINT, { method: "POST", mode: "no-cors", body: JSON.stringify(payload) });
        textarea.value = "";
        textarea.disabled = true;
        submit.textContent = "Tack för att du svarade!";
        submit.disabled = true;
      } catch (err) {
        console.error("Failed to send reasoning", err);
        submit.textContent = "Tack för att du svarade!";
        submit.disabled = true;
      }
    });

    actions.appendChild(submit);
    box.appendChild(actions);
    els.commentsContainer.appendChild(box);
  }

  els.progressText.textContent = "";
  els.progressBarInner.style.width = "0%";

  // Hide Nästa on the outro screen (renderCurrent already handles Tidigare and Avsluta)
  els.btnNext.hidden = true;
  els.btnNext.style.display = "none";

  updateScoreSummary();
}

function renderCurrent() {
  // Tidigare: always hidden on every screen
  els.btnPrev.hidden = true;
  els.btnPrev.style.display = "none";

  // Avsluta: visible on all screens except intro and outro
  const showExit = mode !== "intro" && mode !== "outro";
  els.btnExit.hidden = !showExit;
  els.btnExit.style.display = showExit ? "" : "none";

  // Nästa: always visible (individual render functions set disabled state)
  els.btnNext.hidden = false;
  els.btnNext.style.display = "";

  const shell = document.querySelector(".app-shell");
  if (shell) {
    shell.classList.toggle("theme-comments", mode === "reddit");
    shell.classList.toggle("theme-abstracts", mode === "abstracts");
  }
  if (mode === "intro") {
    renderIntro();
  } else if (mode === "demographics") {
    renderDemographics();
  } else if (mode === "reddit") {
    renderThread();
  } else if (mode === "transition") {
    renderTransition();
  } else if (mode === "outro") {
    renderOutro();
  } else {
    renderQuestion();
  }
}

function resetChoiceStyles() {
  [els.btnHuman, els.btnAi].forEach((btn) => {
    btn.classList.remove("selected", "selected-correct", "selected-incorrect", "disabled");
  });
}

function applyAnswerStyles() {
  const answer = answers[currentIndex];

  if (!answer) return;

  const selectedButton = answer.choiceIsHuman ? els.btnHuman : els.btnAi;

  selectedButton.classList.add("selected");
  [els.btnHuman, els.btnAi].forEach((btn) => btn.classList.add("disabled"));
}

function renderFeedback() {
  // No correctness feedback is shown during the survey.
  els.feedback.textContent = "";
  els.feedback.classList.remove("correct", "incorrect");
}

function updateScoreSummary() {
  const totals = computeTotalScoreSoFar();
  numAnswered = totals.answered;
  numCorrect = totals.correct;

  els.scoreCorrect.textContent = numCorrect.toString();
  els.scoreTotal.textContent = numAnswered.toString();
}

function recordAnswer(choiceIsHuman) {
  if (mode === "abstracts") {
    const existing = answers[currentIndex];
    if (existing) {
      existing.choiceIsHuman = choiceIsHuman;
    } else {
      answers[currentIndex] = { choiceIsHuman };
    }
    hasAnsweredCurrent = true;
    globalQuestionIndex += 1;
    sendAnswerEvent();
    // Auto-advance: jump straight to the next abstract (or the results page).
    if (currentIndex === effectiveQuestions.length - 1) {
      mode = "outro";
      renderOutro();
    } else {
      currentIndex = clampIndex(currentIndex + 1);
      hasAnsweredCurrent = !!answers[currentIndex];
      renderQuestion();
    }
    return;
  }
  if (mode === "reddit" && !redditShowingFeedback) {
    if (!redditAnswers[currentThreadIndex]) {
      redditAnswers[currentThreadIndex] = THREADS[currentThreadIndex].comments.map(() => null);
    }
    redditAnswers[currentThreadIndex][currentCommentIndex] = { choiceIsHuman };
    lastChoiceIsHuman = choiceIsHuman;
    globalQuestionIndex += 1;
    sendAnswerEvent();
    renderThread();
  }
}

function handleNext() {
  if (mode === "intro") {
    mode = "demographics";
    renderDemographics();
    return;
  }
  if (mode === "demographics") {
    sendDemographicsEvent();
    mode = "reddit";
    currentThreadIndex = 0;
    currentCommentIndex = 0;
    redditShowingFeedback = false;
    renderThread();
    return;
  }
  if (mode === "reddit") {
    // Submit all answers for this thread, then advance straight to the next thread
    // (no intermediate review/confirmation screen).
    const thread = THREADS[currentThreadIndex];
    const threadAnswers = redditAnswers[currentThreadIndex] || [];
    for (let c = 0; c < thread.comments.length; c++) {
      if (threadAnswers[c]) {
        globalQuestionIndex += 1;
        currentCommentIndex = c;
        lastChoiceIsHuman = threadAnswers[c].choiceIsHuman;
        sendAnswerEvent();
      }
    }
    if (currentThreadIndex < THREADS.length - 1) {
      currentThreadIndex += 1;
      renderThread();
      return;
    }
    mode = "transition";
    renderTransition();
    return;
  }

  if (mode === "transition") {
    // Start abstracts part
    mode = "abstracts";
    currentIndex = 0;
    hasAnsweredCurrent = !!answers[currentIndex];
    if (els.subtitle) {
      els.subtitle.textContent =
        "Läs abstraktet. Avgör om det är skrivet av en människa eller AI.";
    }
    renderQuestion();
    return;
  }

  if (mode === "outro") {
    // restart
    mode = "intro";
    currentIndex = 0;
    currentThreadIndex = 0;
    currentCommentIndex = 0;
    hasAnsweredCurrent = false;
    numCorrect = 0;
    numAnswered = 0;
    globalQuestionIndex = 0;
    redditAnswers = [];
    redditShowingFeedback = false;
    lastChoiceIsHuman = null;
    demographics = { age: null, profession: "", llmUsage: null, swedishLevel: null };
    renderCurrent();
    return;
  }

  const lastIndex = effectiveQuestions.length - 1;

  if (currentIndex === lastIndex) {
    const percent =
      answers.length === 0
        ? 0
        : Math.round(
            (numCorrect / Math.max(1, answers.filter(Boolean).length)) * 100
          );

    mode = "outro";
    renderOutro();
    return;
  }

  currentIndex = clampIndex(currentIndex + 1);
  hasAnsweredCurrent = !!answers[currentIndex];
  renderQuestion();
}

function handlePrev() {
  if (mode === "reddit") {
    if (redditShowingFeedback) {
      // Dismiss feedback, stay on current thread so user can review before moving on
      redditShowingFeedback = false;
      renderThread();
      return;
    }

    if (currentThreadIndex > 0) {
      currentThreadIndex -= 1;
      renderThread();
      return;
    }
  } else if (mode === "transition") {
    mode = "reddit";
    currentThreadIndex = THREADS.length - 1;
    redditShowingFeedback = true; // show the feedback of the last thread
    renderThread();
  } else if (mode === "abstracts") {
    if (currentIndex === 0) {
      // Go back to the transition screen
      mode = "transition";
      renderTransition();
      return;
    }
    currentIndex = clampIndex(currentIndex - 1);
    hasAnsweredCurrent = !!answers[currentIndex];
    renderQuestion();
  } else if (mode === "outro") {
    // Go back to the last abstracts question
    mode = "abstracts";
    currentIndex = clampIndex(effectiveQuestions.length - 1);
    hasAnsweredCurrent = !!answers[currentIndex];
    renderQuestion();
  }
}

function handleKeydown(event) {
  const target = event.target;
  const tagName = target && target.tagName ? target.tagName.toLowerCase() : "";
  const isTypingField =
    tagName === "textarea" ||
    tagName === "input" ||
    (target && target.isContentEditable);

  // Don't steal keystrokes while the user is typing
  if (isTypingField) return;

  if (event.key === "ArrowLeft") {
    event.preventDefault();
    if (!els.btnPrev.disabled) handlePrev();
  } else if (event.key === "ArrowRight" || event.key === "Enter") {
    event.preventDefault();
    if (!els.btnNext.disabled) handleNext();
  } else if (event.key.toLowerCase() === "h") {
    event.preventDefault();
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(true);
    }
  } else if (event.key.toLowerCase() === "a") {
    event.preventDefault();
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(false);
    }
  }
}

function init() {
  if (els.btnExit) {
    els.btnExit.addEventListener("click", () => {
      mode = "outro";
      renderOutro();
    });
  }
  if (!els.btnHuman || !els.btnAi) {
    console.error("Required DOM elements not found. Check index.html structure.");
    return;
  }

  els.btnHuman.addEventListener("click", () => {
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(true);
    } else if (mode === "reddit" && !redditShowingFeedback) {
      recordAnswer(true);
    }
  });

  els.btnAi.addEventListener("click", () => {
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(false);
    } else if (mode === "reddit" && !redditShowingFeedback) {
      recordAnswer(false);
    }
  });

  els.btnNext.addEventListener("click", handleNext);
  els.btnPrev.addEventListener("click", handlePrev);

  document.addEventListener("keydown", handleKeydown);

  renderCurrent();
}

window.addEventListener("DOMContentLoaded", init);
